mapper.select:
SELECT dh.DEFECT_ID AS defectId, dh.PLANT_CD AS plantCd, dh.RESULT_ID AS resultId, dh.PROC_RESULT_ID AS procResultId, dh.DEFECT_DT AS defectDt, dh.DEFECT_TYPE AS defectType, dh.DEFECT_CD AS defectCd, dh.DEFECT_NM AS defectNm, dh.DEFECT_QTY AS defectQty, dh.DEFECT_CAUSE AS defectCause, dh.DEFECT_ACTION AS defectAction, dh.DISPOSITION AS disposition, dh.DISPOSITION_QTY AS dispositionQty, dh.DISPOSITION_DT AS dispositionDt, dh.ITEM_CD AS itemCd, dh.LOT_NO AS lotNo, dh.WORKER_ID AS workerId, dh.EQUIPMENT_CD AS equipmentCd, dh.PROCESS_CD AS processCd, dh.DEFECT_RMK AS defectRmk, dh.REG_USER_ID AS regUserId, dh.REG_DTM AS regDtm FROM PRD_DEFECT_HIS dh WHERE 1 = 1
AND dh.PLANT_CD = #{plantCd}
AND dh.ITEM_CD = #{itemCd}
AND dh.DEFECT_DT >= #{defectFromDt}
AND dh.DEFECT_DT <= #{defectToDt}
ORDER BY dh.DEFECT_DT DESC, dh.DEFECT_ID DESC
